INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-64311456-moex-00387', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '甲、乙公同共有之土地被徵收，甲針對徵收處分提起撤銷之訴，有關訴訟中乙參加訴訟之敘述，下列 何者錯誤？ 訴訟標的對於甲及乙必須合一確定 行政法院應以裁定命乙參加訴訟 乙之行為有利益於共同訴訟人者，其效力及於全體 乙對於命其參加之裁定得聲明不服', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00388', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '行政法院審查古蹟或歷史建築等文化資產審議決定時，關於判斷餘地之審查，下列敘述何者錯誤？ 法院得審查文化資產審議決定所憑藉的基礎事實是否正確 法院得審查審議程序是否符合正當行政程序及審議委員會之組織是否合法 法院得審查文化資產保存價值判斷之結論與相關學術領域多數見解是否相符 文資審議決定對當事人基本權之限制越重大，應採越高之審查密度', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00389', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '有關透過都市計畫審查程序，請求行政法院宣告都市計畫無效之制度，下列敘述何者正確？ 此類程序以都市計畫發布機關為被告 提起都市計畫審查訴訟前，不須經訴願程序 以都市計畫違法、不當導致直接損害或將損害原告權利或法律上利益為實體裁判要件 為維護法安定性，都市計畫審查訴訟一律於都市計畫發布後1年內之不變期間內提起', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00390', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '甲機關進行土地開發環境影響評估決定後，該決定經最高行政法院判決撤銷確定，關於確定判決效力 之敘述，下列何者正確？ 確定判決有拘束甲機關效力  本於權力分立，甲機關對判決可置之不理 甲機關仍得以原評估決定之理由重為處分  甲機關得另行發布解釋函令，並據以維持原評估決定', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00391', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '依據行政訴訟法之規定，原告之訴該當於下列何者，行政法院不得以裁定逕予駁回？ 本案經終局判決後撤回其訴，復提起同一訴訟  起訴逾越法定期間 原告就已起訴之事件，於訴訟繫屬中更行起訴  原告之訴，依其所訴事實在法律上顯無理由', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00392', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '關於國家賠償法公共設施之國家賠償責任要件，下列敘述何者錯誤？ 國家必須對於該等設施之設置或管理有所欠缺 國家必須對於該等設施具有所有權 人民之損害與設施之設置管理欠缺必須有因果關係 公共設施委由民間團體管理，因管理欠缺而發生損害，國家應負損害賠償責任', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00393', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '關於土地徵收之敘述，下列何者錯誤？ 係以公權力剝奪人民之財產權  財產權人構成特別犧牲 得要求合理補償    得依據法規命令為徵收', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00394', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '有關開放山域等自然公物內之設施，經管理機關已就使用該設施為適當之警告，而人民仍從事具危險 性活動，致其身體受損害時，依國家賠償法之規定國家應負之責任，下列何者正確？ 損害賠償責任', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00395', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '依國家賠償法規定，關於公務員國家賠償之要件，下列敘述何者錯誤？ 行為之公務員須為依公務人員任用法所任用者  必須是執行職務，行使公權力時所生侵害 必須是因故意或過失而侵權者  包含作為與不作為所造成之侵權結果', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00001', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-4d1e9daf', 'sub-aboriginal-6e11b43e-01', NULL, 'essay', '請具體提出清治時期三個文獻資料，並說明該資料如何提供對原住民族
